#include <iostream>#include <vector>#include <algorithm>#include <cmath>#include <string>#include <map>#include <set>#include <iomanip>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    long long a,b,n;    cin >> a >> b >> n;     vll az(n);    for(long long i=0; i<n; i++) cin >> az[i];    long long sum=0;    for(long long i=0;i<n;i++){        sum += min(a-1,az[i]);    }    sum += b;    cout<<sum<<"\n";      } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}